package com.flowmind.common.security;import jakarta.servlet.http.HttpServletRequest;import jakarta.servlet.http.HttpServletResponse;import org.springframework.stereotype.Component;import org.springframework.web.servlet.HandlerInterceptor;@Component public class AuthInterceptor implements HandlerInterceptor{@Override public boolean preHandle(HttpServletRequest request,HttpServletResponse response,Object handler)throws Exception{if("OPTIONS".equalsIgnoreCase(request.getMethod()))return true;String uri=request.getRequestURI();if(uri.startsWith("/api/auth")||uri.startsWith("/v3/api-docs")||uri.startsWith("/swagger-ui")||uri.equals("/actuator/health"))return true;if(!TokenUtil.isValid(request.getHeader("Authorization"))){response.setStatus(401);response.setContentType("application/json;charset=UTF-8");response.getWriter().write("{\"code\":401,\"message\":\"missing or invalid mock token\",\"data\":null}");return false;}return true;}}
